        // Glitch Effect
        const glitchElement = document.getElementById('glitch-text');
        const originalText = glitchElement.innerText;
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ#$@&*";

        setInterval(() => {
            if (Math.random() > 0.9) {
                let glitched = originalText.split('').map(char => {
                    if (Math.random() > 0.8) return chars[Math.floor(Math.random() * chars.length)];
                    return char;
                }).join('');
                glitchElement.innerText = glitched;
                setTimeout(() => {
                    glitchElement.innerText = originalText;
                }, 100);
            }
        }, 150);

        // Scroll Reveal
        const observerOptions = {
            threshold: 0.1
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.style.opacity = '1';
                    entry.target.style.transform = 'translateY(0)';
                }
            });
        }, observerOptions);

